#nullable enable // autogenerated

using System;
using System.Collections;
using MVZ2.Vanilla.Localization;
using MVZ2Logic;
using MVZ2Logic.Commands;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using PVZEngine;

namespace MVZ2.GameContent.Commands
{
    [AutoCommandDefinition(VanillaCommandNames.gotolevel)]
    public class GotoLevel : CommandDefinition
    {
        public GotoLevel(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Invoke(string[] parameters)
        {
            var level = Global.Level;
            if (level.IsInLevel())
            {
                throw new ArgumentException(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_CANNOT_BE_CALLED_IN_LEVEL, LogicStrings.CONTEXT_COMMAND_OUTPUT));
            }
            var stageID = NamespaceID.Parse(parameters[0], Global.BuiltinNamespace);
            var areaID = NamespaceID.Parse(parameters[1], Global.BuiltinNamespace);
            Global.Game.StartCoroutine(Coroutine(areaID, stageID));
        }
        private IEnumerator Coroutine(NamespaceID areaID, NamespaceID stageID)
        {
            var scene = Global.Scene;
            var level = Global.Level;
            yield return scene.GotoLevelCoroutine();
            level.InitLevel(areaID, stageID);
        }
    }
}